Rules.InvariantScript:
Reset(PenInputPas);
Set(varLoading, true);
Set(
    varOrientacao,
    If(App.Width > App.Height, "Paisagem", "Retrato")
);


ClearCollect(colCameras, Camera2.AvailableDevices);

Set(
    varCameraTraseira,
    Coalesce(
        LookUp(colCameras, "Back" in Name).Id,
        First(colCameras).Id
    )
);

Set(
    varCameraFrontal,
    Coalesce(
        LookUp(colCameras, "Front" in Name).Id,
        Last(colCameras).Id
    )
);

Set(varCameraAtual, 0);


Set(varLoading, false);

ControlPropertyState.AutoRuleBindingString:
Set(varLoading, true);

Set(
    varDetalheAtual,
    {
        Tipo:       varServicoSelecionado.Tipo,
        HasServico: !IsBlank(varServicoSelecionado.Servico) && varServicoSelecionado.Tipo = "SERVICO",
        HasTroca:   !IsBlank(varServicoSelecionado.Troca)   && varServicoSelecionado.Tipo = "TROCA",
        HasManut:   !IsBlank(varServicoSelecionado.Manut)   && varServicoSelecionado.Tipo = "MANUTENCAO",
        Servico:    varServicoSelecionado.Servico,
        Troca:      varServicoSelecionado.Troca,
        Manut:      varServicoSelecionado.Manut,
        ManutGeral: varServicoSelecionado.ManutGeral
    }
);

Set(varLoading, false)

Rules.InvariantScript:
// Opção 1: Salvar em uma variável (apenas 1 foto)
Set(varFotoTirada, Camera2.Stream);

Navigate(TelaPreviewFotoManutenção, ScreenTransition.Fade)

ControlPropertyState.AutoRuleBindingString:
Set(varLoading, true);
Set(varAssPas, Substitute(JSON(PenInputPas_1.Image, JSONFormat.IncludeBinaryData), """", ""));
Set(varHorarioFinal, Now());
Navigate(TelaVoucher, ScreenTransition.Cover);
Set(varLoading, false)

Rules.InvariantScript:
ClearCollect(colCameras, Camera2.AvailableDevices);

Set(
    varCameraTraseira,
    Coalesce(
        LookUp(colCameras, "Back" in Name).Id,
        First(colCameras).Id
    )
);

Set(
    varCameraFrontal,
    Coalesce(
        LookUp(colCameras, "Front" in Name).Id,
        Last(colCameras).Id
    )
);

Set(
    varCameraAtual,
    If(
        varCameraAtual = varCameraTraseira,
        varCameraFrontal,
        If(varCameraAtual <> 0,
        varCameraTraseira,
        varCameraFrontal)
    )
)

ControlPropertyState.AutoRuleBindingString:
// Opção 1: Salvar em uma variável (apenas 1 foto)
Set(varFotoTirada, Camera2.Stream);

Navigate(TelaPreviewFotoManutenção, ScreenTransition.Fade)
